    public uint ID;                          // widget id owning the text state
    public int TextLen;                      // UTF-8 length of the string in TextA (in bytes)
    public byte* TextSrc;                    // == TextA.Data unless read-only, in which case == buf passed to InputText(). For _ReadOnly fields, pointer will be null outside the InputText() call.
    public ImVector_char TextA;              // main UTF8 buffer. TextA.Size is a buffer size! Should always be >= buf_size passed by user (and of course >= CurLenA + 1).
    public ImVector_char TextToRevertTo;     // value to revert to when pressing Escape = backup of end-user buffer at the time of focus (in UTF-8, unaltered)
    public ImVector_char CallbackTextBackup; // temporary storage for callback to support automatic reconcile of undo-stack
    public int BufCapacity;                  // end-user buffer capacity (include zero terminator)
    public ImVec2 Scroll;                    // horizontal offset (managed manually) + vertical scrolling (pulled from child window's own Scroll.y)
    public int LineCount;                    // last line count (solely for debugging)
    public float WrapWidth;                  // word-wrapping width
    public float CursorAnim;                 // timer for cursor blink, reset on every user action so the cursor reappears immediately
    public byte CursorFollow;                // set when we want scrolling to follow the current cursor position (not always!)
    public byte CursorCenterY;               // set when we want scrolling to be centered over the cursor position (while resizing a word-wrapping field)
    public byte SelectedAllMouseLock;        // after a double-click to select all, we ignore further mouse drags to update selection
    public byte EditedBefore;                // edited since activated
    public byte EditedThisFrame;             // edited this frame
    public byte WantReloadUserBuf;           // force a reload of user buf so it may be modified externally. may be automatic in future version.
    public sbyte LastMoveDirectionLR;        // ImGuiDir_Left or ImGuiDir_Right. track last movement direction so when cursor cross over a word-wrapping boundaries we can display it on either line depending on last move.s
