/// <summary>
/// Transient per-window data, reset at the beginning of the frame. This used to be called ImGuiDrawContext, hence the DC variable name in ImGuiWindow.
/// (That's theory, in practice the delimitation between ImGuiWindow and ImGuiWindowTempData is quite tenuous and could be reconsidered..)
/// (This doesn't need a constructor because we zero-clear it as part of ImGuiWindow and all frame-temporary data are setup on Begin)
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct WindowTempData
{
    public ImVec2 CursorPos;                   // Current emitting position, in absolute coordinates.
    public ImVec2 CursorPosPrevLine;
    public ImVec2 CursorStartPos;              // Initial position after Begin(), generally ~ window position + WindowPadding.
    public ImVec2 CursorMaxPos;                // Used to implicitly calculate ContentSize at the beginning of next frame, for scrolling range and auto-resize. Always growing during the frame.
    public ImVec2 IdealMaxPos;                 // Used to implicitly calculate ContentSizeIdeal at the beginning of next frame, for auto-resize only. Always growing during the frame.
    public ImVec2 CurrLineSize;
    public ImVec2 PrevLineSize;
    public float CurrLineTextBaseOffset;       // Baseline offset (0.0f by default on a new line, generally == style.FramePadding.y when a framed item has been added).
    public float PrevLineTextBaseOffset;
    public byte IsSameLine;
    public byte IsSetPos;
    public ImVec1 Indent;                      // Indentation / start position from left of window (increased by TreePush/TreePop, etc.)
    public ImVec1 ColumnsOffset;               // Offset to the current column (if ColumnsCurrent > 0). FIXME: This and the above should be a stack to allow use cases like Tree->Column->Tree. Need revamp columns API.
    public ImVec1 GroupOffset;
    public ImVec2 CursorStartPosLossyness;     // Record the loss of precision of CursorStartPos due to really large scrolling amount. This is used by clipper to compensate and fix the most common use case of large scroll area.
    public NavLayer NavLayerCurrent;           // Current layer, 0..31 (we currently only use 0..1)
    public short NavLayersActiveMask;          // Which layers have been written to (result from previous frame)
    public short NavLayersActiveMaskNext;      // Which layers have been written to (accumulator for current frame)
    public byte NavIsScrollPushableX;          // Set when current work location may be scrolled horizontally when moving left / right. This is generally always true UNLESS within a column.
    public byte NavHideHighlightOneFrame;
    public byte NavWindowHasScrollY;           // Set per window when scrolling can be used (== ScrollMax.y > 0.0f)
    public byte MenuBarAppending;              // FIXME: Remove this
    public ImVec2 MenuBarOffset;               // MenuBarOffset.x is sort of equivalent of a per-layer CursorPos.x, saved/restored as we switch to the menu bar. The only situation when MenuBarOffset.y is > 0 if when (SafeAreaPadding.y > FramePadding.y), often used on TVs.
    public MenuColumns MenuColumns;            // Simplified columns storage for menu items measurement
    public int TreeDepth;                      // Current tree depth.
    public uint TreeHasStackDataDepthMask;     // Store whether given depth has ImGuiTreeNodeStackData data. Could be turned into a ImU64 if necessary.
    public uint TreeRecordsClippedNodesY2Mask; // Store whether we should keep recording Y2. Cleared when passing clip max. Equivalent TreeHasStackDataDepthMask value should always be set.
    public ImVector_ImGuiWindowPtr ChildWindows;
    public Storage* StateStorage;              // Current persistent per-window storage (store e.g. tree node open/close state)
    public OldColumns* CurrentColumns;         // Current columns set
    public int CurrentTableIdx;                // Current table index (into g.Tables)
    public LayoutType LayoutType;
    public LayoutType ParentLayoutType;        // Layout type of parent window at the time of Begin()
    public uint ModalDimBgColor;
    public ItemStatusFlags WindowItemStatusFlags;
    public ItemStatusFlags ChildItemStatusFlags;
    public ItemStatusFlags DockTabItemStatusFlags;
    public ImRect DockTabItemRect;
    public float ItemWidth;                    // Current item width (>0.0: width in pixels, <0.0: align xx pixels to the right of window).
    public float ItemWidthDefault;
    public float TextWrapPos;                  // Current text wrap pos.
    public ImVector_float ItemWidthStack;      // Store item widths to restore (attention: .back() is not == ItemWidth)
    public ImVector_float TextWrapPosStack;    // Store text wrap pos to restore (attention: .back() is not == TextWrapPos)
}

/// <summary>
/// Storage for one window
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct Window
{
    public Context* Ctx;                                                     // Parent UI context (needs to be set explicitly by parent).
    public byte* Name;                                                       // Window name, owned by the window.
    public uint ID;                                                          // == ImHashStr(Name)
    public WindowFlags Flags;                                                // See enum ImGuiWindowFlags_
    public WindowFlags FlagsPreviousFrame;                                   // See enum ImGuiWindowFlags_
    public ChildFlags ChildFlags;                                            // Set when window is a child window. See enum ImGuiChildFlags_
    public WindowClass WindowClass;                                          // Advanced users only. Set with SetNextWindowClass()
    public ViewportP* Viewport;                                              // Always set in Begin(). Inactive windows may have a NULL value here if their viewport was discarded.
    public uint ViewportId;                                                  // We backup the viewport id (since the viewport may disappear or never be created if the window is inactive)
    public ImVec2 ViewportPos;                                               // We backup the viewport position (since the viewport may disappear or never be created if the window is inactive)
    public int ViewportAllowPlatformMonitorExtend;                           // Reset to -1 every frame (index is guaranteed to be valid between NewFrame..EndFrame), only used in the Appearing frame of a tooltip/popup to enforce clamping to a given monitor
    public ImVec2 Pos;                                                       // Position (always rounded-up to nearest pixel)
    public ImVec2 Size;                                                      // Current size (==SizeFull or collapsed title bar size)
    public ImVec2 SizeFull;                                                  // Size when non collapsed
    public ImVec2 ContentSize;                                               // Size of contents/scrollable client area (calculated from the extents reach of the cursor) from previous frame. Does not include window decoration or window padding.
    public ImVec2 ContentSizeIdeal;
    public ImVec2 ContentSizeExplicit;                                       // Size of contents/scrollable client area explicitly request by the user via SetNextWindowContentSize().
    public ImVec2 WindowPadding;                                             // Window padding at the time of Begin().
    public float WindowRounding;                                             // Window rounding at the time of Begin(). May be clamped lower to avoid rendering artifacts with title bar, menu bar etc.
    public float WindowBorderSize;                                           // Window border size at the time of Begin().
    public float TitleBarHeight;                                             // Note that those used to be function before 2024/05/28. If you have old code calling TitleBarHeight() you can change it to TitleBarHeight.
    public float MenuBarHeight;                                              // Note that those used to be function before 2024/05/28. If you have old code calling TitleBarHeight() you can change it to TitleBarHeight.
    public float DecoOuterSizeX1;                                            // Left/Up offsets. Sum of non-scrolling outer decorations (X1 generally == 0.0f. Y1 generally = TitleBarHeight + MenuBarHeight). Locked during Begin().
    public float DecoOuterSizeY1;                                            // Left/Up offsets. Sum of non-scrolling outer decorations (X1 generally == 0.0f. Y1 generally = TitleBarHeight + MenuBarHeight). Locked during Begin().
    public float DecoOuterSizeX2;                                            // Right/Down offsets (X2 generally == ScrollbarSize.x, Y2 == ScrollbarSizes.y).
    public float DecoOuterSizeY2;                                            // Right/Down offsets (X2 generally == ScrollbarSize.x, Y2 == ScrollbarSizes.y).
    public float DecoInnerSizeX1;                                            // Applied AFTER/OVER InnerRect. Specialized for Tables as they use specialized form of clipping and frozen rows/columns are inside InnerRect (and not part of regular decoration sizes).
    public float DecoInnerSizeY1;                                            // Applied AFTER/OVER InnerRect. Specialized for Tables as they use specialized form of clipping and frozen rows/columns are inside InnerRect (and not part of regular decoration sizes).
    public int NameBufLen;                                                   // Size of buffer storing Name. May be larger than strlen(Name)!
    public uint MoveId;                                                      // == window->GetID("#MOVE")
    public uint TabId;                                                       // == window->GetID("#TAB")
    public uint ChildId;                                                     // ID of corresponding item in parent window (for navigation to return from child window to parent window)
    public uint PopupId;                                                     // ID in the popup stack when this window is used as a popup/menu (because we use generic Name/ID for recycling)
    public ImVec2 Scroll;
    public ImVec2 ScrollMax;
    public ImVec2 ScrollTarget;                                              // target scroll position. stored as cursor position with scrolling canceled out, so the highest point is always 0.0f. (FLT_MAX for no change)
    public ImVec2 ScrollTargetCenterRatio;                                   // 0.0f = scroll so that target position is at top, 0.5f = scroll so that target position is centered
    public ImVec2 ScrollTargetEdgeSnapDist;                                  // 0.0f = no snapping, >0.0f snapping threshold
    public ImVec2 ScrollbarSizes;                                            // Size taken by each scrollbars on their smaller axis. Pay attention! ScrollbarSizes.x == width of the vertical scrollbar, ScrollbarSizes.y = height of the horizontal scrollbar.
    public byte ScrollbarX;                                                  // Are scrollbars visible?
    public byte ScrollbarY;                                                  // Are scrollbars visible?
    public byte ScrollbarXStabilizeEnabled;                                  // Was ScrollbarX previously auto-stabilized?
    public byte ScrollbarXStabilizeToggledHistory;                           // Used to stabilize scrollbar visibility in case of feedback loops
    public byte ViewportOwned;
    public byte Active;                                                      // Set to true on Begin(), unless Collapsed
    public byte WasActive;
    public byte WriteAccessed;                                               // Set to true when any widget access the current window
    public byte Collapsed;                                                   // Set when collapsing window to become only title-bar
    public byte WantCollapseToggle;
    public byte SkipItems;                                                   // Set when items can safely be all clipped (e.g. window not visible or collapsed)
    public byte SkipRefresh;                                                 // [EXPERIMENTAL] Reuse previous frame drawn contents, Begin() returns false.
    public byte Appearing;                                                   // Set during the frame where the window is appearing (or re-appearing)
    public byte Hidden;                                                      // Do not display (== HiddenFrames*** > 0)
    public byte IsFallbackWindow;                                            // Set on the "Debug##Default" window.
    public byte IsExplicitChild;                                             // Set when passed _ChildWindow, left to false by BeginDocked()
    public byte HasCloseButton;                                              // Set when the window has a close button (p_open != NULL)
    public byte ResizeBorderHovered;                                         // Current border being hovered for resize (-1: none, otherwise 0-3)
    public byte ResizeBorderHeld;                                            // Current border being held for resize (-1: none, otherwise 0-3)
    public short BeginCount;                                                 // Number of Begin() during the current frame (generally 0 or 1, 1+ if appending via multiple Begin/End pairs)
    public short BeginCountPreviousFrame;                                    // Number of Begin() during the previous frame
    public short BeginOrderWithinParent;                                     // Begin() order within immediate parent window, if we are a child window. Otherwise 0.
    public short BeginOrderWithinContext;                                    // Begin() order within entire imgui context. This is mostly used for debugging submission order related issues.
    public short FocusOrder;                                                 // Order within WindowsFocusOrder[], altered when windows are focused.
    public Dir AutoPosLastDirection;
    public sbyte AutoFitFramesX;
    public sbyte AutoFitFramesY;
    public byte AutoFitOnlyGrows;
    public sbyte HiddenFramesCanSkipItems;                                   // Hide the window for N frames
    public sbyte HiddenFramesCannotSkipItems;                                // Hide the window for N frames while allowing items to be submitted so we can measure their size
    public sbyte HiddenFramesForRenderOnly;                                  // Hide the window until frame N at Render() time only
    public sbyte DisableInputsFrames;                                        // Disable window interactions for N frames
    public WindowBgClickFlags BgClickFlags;                                  // Configure behavior of click+dragging on window bg/void or over items. Default sets by io.ConfigWindowsMoveFromTitleBarOnly. If you use this please report in #3379.
    public Cond SetWindowPosAllowFlags;                                      // store acceptable condition flags for SetNextWindowPos() use.
    public Cond SetWindowSizeAllowFlags;                                     // store acceptable condition flags for SetNextWindowSize() use.
    public Cond SetWindowCollapsedAllowFlags;                                // store acceptable condition flags for SetNextWindowCollapsed() use.
    public Cond SetWindowDockAllowFlags;                                     // store acceptable condition flags for SetNextWindowDock() use.
    public ImVec2 SetWindowPosVal;                                           // store window position when using a non-zero Pivot (position set needs to be processed when we know the window size)
    public ImVec2 SetWindowPosPivot;                                         // store window pivot for positioning. ImVec2(0, 0) when positioning from top-left corner; ImVec2(0.5f, 0.5f) for centering; ImVec2(1, 1) for bottom right.
    public ImVector_ImGuiID IDStack;                                         // ID stack. ID are hashes seeded with the value at the top of the stack. (In theory this should be in the TempData structure)
    public WindowTempData DC;                                                // Temporary per-window data, reset at the beginning of the frame. This used to be called ImGuiDrawContext, hence the "DC" variable name.
    public ImRect OuterRectClipped;                                          // == Window->Rect() just after setup in Begin(). == window->Rect() for root window.
    public ImRect InnerRect;                                                 // Inner rectangle (omit title bar, menu bar, scroll bar)
    public ImRect InnerClipRect;                                             // == InnerRect shrunk by WindowPadding*0.5f on each side, clipped within viewport or parent clip rect.
    public ImRect WorkRect;                                                  // Initially covers the whole scrolling region. Reduced by containers e.g columns/tables when active. Shrunk by WindowPadding*1.0f on each side. This is meant to replace ContentRegionRect over time (from 1.71+ onward).
    public ImRect ParentWorkRect;                                            // Backup of WorkRect before entering a container such as columns/tables. Used by e.g. SpanAllColumns functions to easily access. Stacked containers are responsible for maintaining this. // FIXME-WORKRECT: Could be a stack?
    public ImRect ClipRect;                                                  // Current clipping/scissoring rectangle, evolve as we are using PushClipRect(), etc. == DrawList->clip_rect_stack.back().
    public ImRect ContentRegionRect;                                         // FIXME: This is currently confusing/misleading. It is essentially WorkRect but not handling of scrolling. We currently rely on it as right/bottom aligned sizing operation need some size to rely on.
    public ImVec2ih HitTestHoleSize;                                         // Define an optional rectangular hole where mouse will pass-through the window.
    public ImVec2ih HitTestHoleOffset;
    public int LastFrameActive;                                              // Last frame number the window was Active.
    public int LastFrameJustFocused;                                         // Last frame number the window was made Focused.
    public float LastTimeActive;                                             // Last timestamp the window was Active (using float as we don't need high precision there)
    public Storage StateStorage;
    public ImVector_ImGuiOldColumns ColumnsStorage;
    public float FontWindowScale;                                            // User scale multiplier per-window, via SetWindowFontScale()
    public float FontWindowScaleParents;
    public float FontRefSize;                                                // This is a copy of window->CalcFontSize() at the time of Begin(), trying to phase out CalcFontSize() especially as it may be called on non-current window.
    public int SettingsOffset;                                               // Offset into SettingsWindows[] (offsets are always valid as we only grow the array from the back)
    public ImDrawList* DrawList;                                             // == &DrawListInst (for backward compatibility reason with code using imgui_internal.h we keep this a pointer)
    public ImDrawList DrawListInst;
    public Window* ParentWindow;                                             // If we are a child _or_ popup _or_ docked window, this is pointing to our parent. Otherwise NULL.
    public Window* ParentWindowInBeginStack;
    public Window* RootWindow;                                               // Point to ourself or first ancestor that is not a child window. Doesn't cross through popups/dock nodes.
    public Window* RootWindowPopupTree;                                      // Point to ourself or first ancestor that is not a child window. Cross through popups parent<>child.
    public Window* RootWindowDockTree;                                       // Point to ourself or first ancestor that is not a child window. Cross through dock nodes.
    public Window* RootWindowForTitleBarHighlight;                           // Point to ourself or first ancestor which will display TitleBgActive color when this window is active.
    public Window* RootWindowForNav;                                         // Point to ourself or first ancestor which doesn't have the NavFlattened flag.
    public Window* ParentWindowForFocusRoute;                                // Set to manual link a window to its logical parent so that Shortcut() chain are honored (e.g. Tool linked to Document)
    public Window* NavLastChildNavWindow;                                    // When going to the menu bar, we remember the child window we came from. (This could probably be made implicit if we kept g.Windows sorted by last focused including child window.)
    public Window_NavLastIds_Array NavLastIds;                               // Last known NavId for this window, per layer (0/1)
    public Window_NavRectRel_Array NavRectRel;                               // Reference rectangle, in window relative space
    public Window_NavPreferredScoringPosRel_Array NavPreferredScoringPosRel; // Preferred X/Y position updated when moving on a given axis, reset to FLT_MAX.
    public uint NavRootFocusScopeId;                                         // Focus Scope ID at the time of Begin()
    public int MemoryDrawListIdxCapacity;                                    // Backup of last idx/vtx count, so when waking up the window we can preallocate and avoid iterative alloc/copy
    public int MemoryDrawListVtxCapacity;
    public byte MemoryCompacted;                                             // Set when window extraneous data have been garbage collected
    public byte DockIsActive;                                                // When docking artifacts are actually visible. When this is set, DockNode is guaranteed to be != NULL. ~~ (DockNode != NULL) && (DockNode->Windows.Size > 1).
    public byte DockNodeIsVisible;
    public byte DockTabIsVisible;                                            // Is our window visible this frame? ~~ is the corresponding tab selected?
    public byte DockTabWantClose;
    public short DockOrder;                                                  // Order of the last time the window was visible within its DockNode. This is used to reorder windows that are reappearing on the same frame. Same value between windows that were active and windows that were none are possible.
    public WindowDockStyle DockStyle;
    public DockNode* DockNode;                                               // Which node are we docked into. Important: Prefer testing DockIsActive in many cases as this will still be set when the dock node is hidden.
    public DockNode* DockNodeAsHost;                                         // Which node are we owning (for parent windows)
    public uint DockId;                                                      // Backup of last valid DockNode->ID, so single window remember their dock node id even when they are not bound any more
}

/// <summary>
