    public float Offset;            // Position relative to beginning of tab bar
    public float Width;             // Width currently displayed
    public float ContentWidth;      // Width of label + padding, stored during BeginTabItem() call (misnamed as "Content" would normally imply width of label only)
    public float RequestedWidth;    // Width optionally requested by caller, -1.0f is unused
    public int NameOffset;          // When Window==NULL, offset to name within parent ImGuiTabBar::TabsNames
    public short BeginOrder;        // BeginTabItem() order, used to re-order tabs after toggling ImGuiTabBarFlags_Reorderable
    public short IndexDuringLayout; // Index only used during TabBarLayout(). Tabs gets reordered so 'Tabs[n].IndexDuringLayout == n' but may mismatch during additions.
    public byte WantClose;          // Marked as closed by SetTabItemClosed()
}

