/// <summary>
/// [Internal] sizeof() ~ 112
/// We use the terminology "Enabled" to refer to a column that is not Hidden by user/api.
/// We use the terminology "Clipped" to refer to a column that is out of sight because of scrolling/clipping.
/// This is in contrast with some user-facing api such as IsItemVisible() / IsRectVisible() which use "Visible" to mean "not clipped".
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public partial struct TableColumn
{
    public TableColumnFlags Flags;         // Flags after some patching (not directly same as provided by user). See ImGuiTableColumnFlags_
    public float WidthGiven;               // Final/actual width visible == (MaxX - MinX), locked in TableUpdateLayout(). May be > WidthRequest to honor minimum width, may be < WidthRequest to honor shrinking columns down in tight space.
    public float MinX;                     // Absolute positions
    public float MaxX;
    public float WidthRequest;             // Master width absolute value when !(Flags & _WidthStretch). When Stretch this is derived every frame from StretchWeight in TableUpdateLayout()
    public float WidthAuto;                // Automatic width
    public float WidthMax;                 // Maximum width (FIXME: overwritten by each instance)
    public float StretchWeight;            // Master width weight when (Flags & _WidthStretch). Often around ~1.0f initially.
    public float InitStretchWeightOrWidth; // Value passed to TableSetupColumn(). For Width it is a content width (_without padding_).
    public ImRect ClipRect;                // Clipping rectangle for the column
    public uint UserID;                    // Optional, value passed to TableSetupColumn()
    public float WorkMinX;                 // Contents region min ~(MinX + CellPaddingX + CellSpacingX1) == cursor start position when entering column
    public float WorkMaxX;                 // Contents region max ~(MaxX - CellPaddingX - CellSpacingX2)
    public float ItemWidth;                // Current item width for the column, preserved across rows
    public float ContentMaxXFrozen;        // Contents maximum position for frozen rows (apart from headers), from which we can infer content width.
    public float ContentMaxXUnfrozen;
    public float ContentMaxXHeadersUsed;   // Contents maximum position for headers rows (regardless of freezing). TableHeader() automatically softclip itself + report ideal desired size, to avoid creating extraneous draw calls
    public float ContentMaxXHeadersIdeal;
    public short NameOffset;               // Offset into parent ColumnsNames[]
    public short DisplayOrder;             // Index within Table's IndexToDisplayOrder[] (column may be reordered by users)
    public short IndexWithinEnabledSet;    // Index within enabled/visible set (<= IndexToDisplayOrder)
    public short PrevEnabledColumn;        // Index of prev enabled/visible column within Columns[], -1 if first enabled/visible column
    public short NextEnabledColumn;        // Index of next enabled/visible column within Columns[], -1 if last enabled/visible column
    public short SortOrder;                // Index of this column within sort specs, -1 if not sorting on this column, 0 for single-sort, may be >0 on multi-sort
    public ushort DrawChannelCurrent;      // Index within DrawSplitter.Channels[]
    public ushort DrawChannelFrozen;       // Draw channels for frozen rows (often headers)
    public ushort DrawChannelUnfrozen;     // Draw channels for unfrozen rows
    public byte IsEnabled;                 // IsUserEnabled && (Flags & ImGuiTableColumnFlags_Disabled) == 0
    public byte IsUserEnabled;             // Is the column not marked Hidden by the user? (unrelated to being off view, e.g. clipped by scrolling).
    public byte IsUserEnabledNextFrame;
    public byte IsVisibleX;                // Is actually in view (e.g. overlapping the host window clipping rectangle, not scrolled).
    public byte IsVisibleY;
    public byte IsRequestOutput;           // Return value for TableSetColumnIndex() / TableNextColumn(): whether we request user to output contents or not.
    public byte IsSkipItems;               // Do we want item submissions to this column to be completely ignored (no layout will happen).
    public byte IsPreserveWidthAuto;
    public sbyte NavLayerCurrent;          // ImGuiNavLayer in 1 byte
    public byte AutoFitQueue;              // Queue of 8 values for the next 8 frames to request auto-fit
    public byte CannotSkipItemsQueue;      // Queue of 8 values for the next 8 frames to disable Clipped/SkipItem
    public byte SortDirection;             // ImGuiSortDirection_Ascending or ImGuiSortDirection_Descending
    public byte SortDirectionsAvailCount;  // Number of available sort directions (0 to 3)
    public byte SortDirectionsAvailMask;   // Mask of available sort directions (1-bit each)
    public byte SortDirectionsAvailList;   // Ordered list of available sort directions (2-bits each, total 8-bits)
}

/// <summary>
/// Transient cell data stored per row.
