    public float RowCellPaddingY;                             // Top and bottom padding. Reloaded during row change.
    public float RowTextBaseline;
    public float RowIndentOffsetX;
    public TableRowFlags RowFlags;                            // Current row flags, see ImGuiTableRowFlags_
    public TableRowFlags LastRowFlags;
    public int RowBgColorCounter;                             // Counter for alternating background colors (can be fast-forwarded by e.g clipper), not same as CurrentRow because header rows typically don't increase this.
    public fixed uint RowBgColor[2];                          // Background color override for current row.
    public uint BorderColorStrong;
    public uint BorderColorLight;
    public float BorderX1;
    public float BorderX2;
    public float HostIndentX;
    public float MinColumnWidth;
    public float OuterPaddingX;
    public float CellPaddingX;                                // Padding from each borders. Locked in BeginTable()/Layout.
    public float CellSpacingX1;                               // Spacing between non-bordered cells. Locked in BeginTable()/Layout.
    public float CellSpacingX2;
    public float InnerWidth;                                  // User value passed to BeginTable(), see comments at the top of BeginTable() for details.
    public float ColumnsGivenWidth;                           // Sum of current column width
    public float ColumnsAutoFitWidth;                         // Sum of ideal column width in order nothing to be clipped, used for auto-fitting and content width submission in outer window
    public float ColumnsStretchSumWeights;                    // Sum of weight of all enabled stretching columns
    public float ResizedColumnNextWidth;
    public float ResizeLockMinContentsX2;                     // Lock minimum contents width while resizing down in order to not create feedback loops. But we allow growing the table.
    public float RefScale;                                    // Reference scale to be able to rescale columns on font/dpi changes.
    public float AngledHeadersHeight;                         // Set by TableAngledHeadersRow(), used in TableUpdateLayout()
    public float AngledHeadersSlope;                          // Set by TableAngledHeadersRow(), used in TableUpdateLayout()
    public ImRect OuterRect;                                  // Note: for non-scrolling table, OuterRect.Max.y is often FLT_MAX until EndTable(), unless a height has been specified in BeginTable().
    public ImRect InnerRect;                                  // InnerRect but without decoration. As with OuterRect, for non-scrolling tables, InnerRect.Max.y is "
    public ImRect WorkRect;
    public ImRect InnerClipRect;
    public ImRect BgClipRect;                                 // We use this to cpu-clip cell background color fill, evolve during the frame as we cross frozen rows boundaries
    public ImRect Bg0ClipRectForDrawCmd;                      // Actual ImDrawCmd clip rect for BG0/1 channel. This tends to be == OuterWindow->ClipRect at BeginTable() because output in BG0/BG1 is cpu-clipped
    public ImRect Bg2ClipRectForDrawCmd;                      // Actual ImDrawCmd clip rect for BG2 channel. This tends to be a correct, tight-fit, because output to BG2 are done by widgets relying on regular ClipRect.
    public ImRect HostClipRect;                               // This is used to check if we can eventually merge our columns draw calls into the current draw call of the current window.
    public ImRect HostBackupInnerClipRect;                    // Backup of InnerWindow->ClipRect during PushTableBackground()/PopTableBackground()
    public Window* OuterWindow;                               // Parent window for the table
    public Window* InnerWindow;                               // Window holding the table data (== OuterWindow or a child window)
    public TextBuffer ColumnsNames;                           // Contiguous buffer holding columns names
    public ImDrawListSplitter* DrawSplitter;                  // Shortcut to TempData->DrawSplitter while in table. Isolate draw commands per columns to avoid switching clip rect constantly
    public TableInstanceData InstanceDataFirst;
    public ImVector_ImGuiTableInstanceData InstanceDataExtra; // FIXME-OPT: Using a small-vector pattern would be good.
    public TableColumnSortSpecs SortSpecsSingle;
    public ImVector_ImGuiTableColumnSortSpecs SortSpecsMulti; // FIXME-OPT: Using a small-vector pattern would be good.
    public TableSortSpecs SortSpecs;                          // Public facing sorts specs, this is what we return in TableGetSortSpecs()
    public short SortSpecsCount;
    public short ColumnsEnabledCount;                         // Number of enabled columns (<= ColumnsCount)
    public short ColumnsEnabledFixedCount;                    // Number of enabled columns using fixed width (<= ColumnsCount)
    public short DeclColumnsCount;                            // Count calls to TableSetupColumn()
    public short AngledHeadersCount;                          // Count columns with angled headers
    public short HoveredColumnBody;                           // Index of column whose visible region is being hovered. Important: == ColumnsCount when hovering empty region after the right-most column!
    public short HoveredColumnBorder;                         // Index of column whose right-border is being hovered (for resizing).
    public short HighlightColumnHeader;                       // Index of column which should be highlighted.
    public short AutoFitSingleColumn;                         // Index of single column requesting auto-fit.
    public short ResizedColumn;                               // Index of column being resized. Reset when InstanceCurrent==0.
    public short LastResizedColumn;                           // Index of column being resized from previous frame.
    public short HeldHeaderColumn;                            // Index of column header being held.
    public short LastHeldHeaderColumn;                        // Index of column header being held from previous frame.
    public short ReorderColumn;                               // Index of column being reordered. (not cleared)
    public short ReorderColumnDstOrder;                       // Requested display order of column being reordered.
    public short LeftMostEnabledColumn;                       // Index of left-most non-hidden column.
    public short RightMostEnabledColumn;                      // Index of right-most non-hidden column.
    public short LeftMostStretchedColumn;                     // Index of left-most stretched column.
    public short RightMostStretchedColumn;                    // Index of right-most stretched column.
    public short ContextPopupColumn;                          // Column right-clicked on, of -1 if opening context menu from a neutral/empty spot
    public short FreezeRowsRequest;                           // Requested frozen rows count
    public short FreezeRowsCount;                             // Actual frozen row count (== FreezeRowsRequest, or == 0 when no scrolling offset)
    public short FreezeColumnsRequest;                        // Requested frozen columns count
    public short FreezeColumnsCount;                          // Actual frozen columns count (== FreezeColumnsRequest, or == 0 when no scrolling offset)
    public short RowCellDataCurrent;                          // Index of current RowCellData[] entry in current row
    public ushort DummyDrawChannel;                           // Redirect non-visible columns here.
    public ushort Bg2DrawChannelCurrent;                      // For Selectable() and other widgets drawing across columns after the freezing line. Index within DrawSplitter.Channels[]
    public ushort Bg2DrawChannelUnfrozen;
    public sbyte NavLayer;                                    // ImGuiNavLayer at the time of BeginTable().
    public byte IsLayoutLocked;                               // Set by TableUpdateLayout() which is called when beginning the first row.
    public byte IsInsideRow;                                  // Set when inside TableBeginRow()/TableEndRow().
    public byte IsInitializing;
    public byte IsSortSpecsDirty;
    public byte IsUsingHeaders;                               // Set when the first row had the ImGuiTableRowFlags_Headers flag.
    public byte IsContextPopupOpen;                           // Set when default context menu is open (also see: ContextPopupColumn, InstanceInteracted).
    public byte DisableDefaultContextMenu;                    // Disable default context menu. You may submit your own using TableBeginContextMenuPopup()/EndPopup()
    public byte IsSettingsRequestLoad;
    public byte IsSettingsDirty;                              // Set when table settings have changed and needs to be reported into ImGuiTableSettings data.
    public byte IsDefaultDisplayOrder;                        // Set when display order is unchanged from default (DisplayOrder contains 0...Count-1)
    public byte IsResetAllRequest;
    public byte IsResetDisplayOrderRequest;
    public byte IsUnfrozenRows;                               // Set when we got past the frozen row.
    public byte IsDefaultSizingPolicy;                        // Set if user didn't explicitly set a sizing policy in BeginTable()
    public byte IsActiveIdAliveBeforeTable;
    public byte IsActiveIdInTable;
    public byte HasScrollbarYCurr;                            // Whether ANY instance of this table had a vertical scrollbar during the current frame.
    public byte HasScrollbarYPrev;                            // Whether ANY instance of this table had a vertical scrollbar during the previous.
    public byte MemoryCompacted;
    public byte HostSkipItems;                                // Backup of InnerWindow->SkipItem at the end of BeginTable(), because we will overwrite InnerWindow->SkipItem on a per-column basis
}

